// Handler creates http.Handler with routing matching OpenAPI spec.
func Handler(si ServerInterface) http.Handler {
	return HandlerWithOptions(si, ChiServerOptions{})
}

type ChiServerOptions struct {
	BaseURL          string
	BaseRouter       chi.Router
	Middlewares      []MiddlewareFunc
	ErrorHandlerFunc func(w http.ResponseWriter, r *http.Request, err error)
}

// HandlerFromMux creates http.Handler with routing matching OpenAPI spec based on the provided mux.
func HandlerFromMux(si ServerInterface, r chi.Router) http.Handler {
	return HandlerWithOptions(si, ChiServerOptions{
		BaseRouter: r,
	})
}

func HandlerFromMuxWithBaseURL(si ServerInterface, r chi.Router, baseURL string) http.Handler {
	return HandlerWithOptions(si, ChiServerOptions{
		BaseURL:    baseURL,
		BaseRouter: r,
	})
}

// HandlerWithOptions creates http.Handler with additional options
func HandlerWithOptions(si ServerInterface, options ChiServerOptions) http.Handler {
	r := options.BaseRouter

	if r == nil {
		r = chi.NewRouter()
	}
	if options.ErrorHandlerFunc == nil {
		options.ErrorHandlerFunc = func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusBadRequest)
		}
	}
	wrapper := ServerInterfaceWrapper{
		Handler:            si,
		HandlerMiddlewares: options.Middlewares,
		ErrorHandlerFunc:   options.ErrorHandlerFunc,
	}

	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/admin/dashboard", wrapper.GetDashboard)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/admin/reply-templates", wrapper.ListReplyTemplates)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/admin/settings", wrapper.GetSettings)
	})
	r.Group(func(r chi.Router) {
		r.Patch(options.BaseURL+"/admin/settings/bank-account", wrapper.UpdateBankAccount)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/auth/login", wrapper.LoginUser)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/auth/logout", wrapper.LogoutUser)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/categories", wrapper.GetCategories)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/customer/login", wrapper.LoginCustomer)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/customer/logout", wrapper.LogoutCustomer)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/customer/orders", wrapper.GetCustomerOrders)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/customer/register", wrapper.RegisterCustomer)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/orders", wrapper.CreateOrder)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/orders/lookup", wrapper.LookupOrder)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/orders/{id}/transitions", wrapper.TransitionOrder)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/price/quote", wrapper.QuotePrice)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/products", wrapper.GetProducts)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/products/{slug}", wrapper.GetProductBySlug)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/products/{slug}/reviews", wrapper.GetProductReviews)
	})

	return r
}

