// StrictServerInterface represents all server handlers.
type StrictServerInterface interface {
	// Admin dashboard aggregates (counts + net revenue + recent orders + todos).
	// (GET /admin/dashboard)
	GetDashboard(ctx context.Context, request GetDashboardRequestObject) (GetDashboardResponseObject, error)
	// List the extension reply templates (admin-gated read).
	// (GET /admin/reply-templates)
	ListReplyTemplates(ctx context.Context, request ListReplyTemplatesRequestObject) (ListReplyTemplatesResponseObject, error)
	// Read the settings singleton (admin-gated).
	// (GET /admin/settings)
	GetSettings(ctx context.Context, request GetSettingsRequestObject) (GetSettingsResponseObject, error)
	// Change the VietQR STK (owner-only; persisted with an append-only audit row).
	// (PATCH /admin/settings/bank-account)
	UpdateBankAccount(ctx context.Context, request UpdateBankAccountRequestObject) (UpdateBankAccountResponseObject, error)
	// Email + password login; sets the session cookie on success.
	// (POST /auth/login)
	LoginUser(ctx context.Context, request LoginUserRequestObject) (LoginUserResponseObject, error)
	// Clear the session cookie.
	// (POST /auth/logout)
	LogoutUser(ctx context.Context, request LogoutUserRequestObject) (LogoutUserResponseObject, error)
	// Public storefront category list — the browsable taxonomy for the catalog-browse chips.
	// (GET /categories)
	GetCategories(ctx context.Context, request GetCategoriesRequestObject) (GetCategoriesResponseObject, error)
	// Email + password login for a storefront customer; sets the customer session cookie.
	// (POST /customer/login)
	LoginCustomer(ctx context.Context, request LoginCustomerRequestObject) (LoginCustomerResponseObject, error)
	// Clear the customer session cookie.
	// (POST /customer/logout)
	LogoutCustomer(ctx context.Context, request LogoutCustomerRequestObject) (LogoutCustomerResponseObject, error)
	// The authenticated customer's own order history (timeline projection).
	// (GET /customer/orders)
	GetCustomerOrders(ctx context.Context, request GetCustomerOrdersRequestObject) (GetCustomerOrdersResponseObject, error)
	// Register a storefront customer account; sets the customer session cookie on success.
	// (POST /customer/register)
	RegisterCustomer(ctx context.Context, request RegisterCustomerRequestObject) (RegisterCustomerResponseObject, error)
	// Create an order (web → PENDING_CONFIRM, public; inbox → PAID, staff/owner only).
	// (POST /orders)
	CreateOrder(ctx context.Context, request CreateOrderRequestObject) (CreateOrderResponseObject, error)
	// Public guest order lookup by code + phone — a minimal, non-leaking timeline.
	// (GET /orders/lookup)
	LookupOrder(ctx context.Context, request LookupOrderRequestObject) (LookupOrderResponseObject, error)
	// Advance an order's status (RBAC-gated; reconcile→PAID and →REFUNDED are owner-only).
	// (POST /orders/{id}/transitions)
	TransitionOrder(ctx context.Context, request TransitionOrderRequestObject) (TransitionOrderResponseObject, error)
	// Server-authoritative line/subtotal quote for a selection (no shipping/address).
	// (POST /price/quote)
	QuotePrice(ctx context.Context, request QuotePriceRequestObject) (QuotePriceResponseObject, error)
	// Public storefront catalog list (active-only) — paginated card projection.
	// (GET /products)
	GetProducts(ctx context.Context, request GetProductsRequestObject) (GetProductsResponseObject, error)
	// Public storefront product detail (active-only) — product + colors + options.
	// (GET /products/{slug})
	GetProductBySlug(ctx context.Context, request GetProductBySlugRequestObject) (GetProductBySlugResponseObject, error)
	// Public storefront product reviews (published-only) — paginated, newest first.
	// (GET /products/{slug}/reviews)
	GetProductReviews(ctx context.Context, request GetProductReviewsRequestObject) (GetProductReviewsResponseObject, error)
}

type StrictHandlerFunc = strictnethttp.StrictHTTPHandlerFunc
type StrictMiddlewareFunc = strictnethttp.StrictHTTPMiddlewareFunc

type StrictHTTPServerOptions struct {
	RequestErrorHandlerFunc  func(w http.ResponseWriter, r *http.Request, err error)
	ResponseErrorHandlerFunc func(w http.ResponseWriter, r *http.Request, err error)
}

func NewStrictHandler(ssi StrictServerInterface, middlewares []StrictMiddlewareFunc) ServerInterface {
	return &strictHandler{ssi: ssi, middlewares: middlewares, options: StrictHTTPServerOptions{
		RequestErrorHandlerFunc: func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusBadRequest)
		},
		ResponseErrorHandlerFunc: func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusInternalServerError)
		},
	}}
}

func NewStrictHandlerWithOptions(ssi StrictServerInterface, middlewares []StrictMiddlewareFunc, options StrictHTTPServerOptions) ServerInterface {
	return &strictHandler{ssi: ssi, middlewares: middlewares, options: options}
}

